('computer-science:1-2-4-data-storage-numbers:match:d1b65b07', 'computer-science', 'computer-science:1-2-4-data-storage-numbers', '1.2.4 Data Storage: Numbers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Carry”?", "options": ["An error that occurs when a calculation''s true result needs more bits than are available to store it", "The everyday base-10 number system, using the digits 0-9", "4 bits — exactly enough to represent one hexadecimal digit (0-F)", "The extra 1 passed into the next column when a binary addition column totals 2 or more"]}'::jsonb, '{"answer": 3, "explain": "“Carry” means: The extra 1 passed into the next column when a binary addition column totals 2 or more"}'::jsonb),
('computer-science:1-2-4-data-storage-numbers:match:5194c5ae', 'computer-science', 'computer-science:1-2-4-data-storage-numbers', '1.2.4 Data Storage: Numbers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Padding”?", "options": ["The base-16 number system, using digits 0-9 and letters A-F", "4 bits — exactly enough to represent one hexadecimal digit (0-F)", "Adding leading zeros so a binary number fills the full number of bits required", "Moving every bit in a binary number left or right by a set number of places, filling the gap with 0s"]}'::jsonb, '{"answer": 2, "explain": "“Padding” means: Adding leading zeros so a binary number fills the full number of bits required"}'::jsonb),
('computer-science:1-2-4-data-storage-numbers:match:604650a3', 'computer-science', 'computer-science:1-2-4-data-storage-numbers', '1.2.4 Data Storage: Numbers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Logical shift”?", "options": ["Moving every bit in a binary number left or right by a set number of places, filling the gap with 0s", "4 bits — exactly enough to represent one hexadecimal digit (0-F)", "The extra 1 passed into the next column when a binary addition column totals 2 or more", "The right-most bit in a binary number — it carries the smallest place value (1)"]}'::jsonb, '{"answer": 0, "explain": "“Logical shift” means: Moving every bit in a binary number left or right by a set number of places, filling the gap with 0s"}'::jsonb),
('computer-science:1-2-4-data-storage-numbers:match:14d77486', 'computer-science', 'computer-science:1-2-4-data-storage-numbers', '1.2.4 Data Storage: Numbers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Effect of a logical LEFT shift”?", "options": ["128, 64, 32, 16, 8, 4, 2, 1 — the value of each bit position", "The base-16 number system, using digits 0-9 and letters A-F", "The left-most bit in a binary number — it carries the largest place value", "Multiplies the original value by 2 for every place shifted"]}'::jsonb, '{"answer": 3, "explain": "“Effect of a logical LEFT shift” means: Multiplies the original value by 2 for every place shifted"}'::jsonb),
('computer-science:1-2-4-data-storage-numbers:match:7eb0d030', 'computer-science', 'computer-science:1-2-4-data-storage-numbers', '1.2.4 Data Storage: Numbers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Effect of a logical RIGHT shift”?", "options": ["Divides the original value by 2 for every place shifted, losing any remainder", "The extra 1 passed into the next column when a binary addition column totals 2 or more", "An error that occurs when a calculation''s true result needs more bits than are available to store it", "The everyday base-10 number system, using the digits 0-9"]}'::jsonb, '{"answer": 0, "explain": "“Effect of a logical RIGHT shift” means: Divides the original value by 2 for every place shifted, losing any remainder"}'::jsonb),
('computer-science:1-2-5-data-storage-characters:exam:0f8358cf', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'exam', 'mcq', 1, '{"num": "P4", "question": "<p>Which of these is the correct number of characters that can be represented by the standard ASCII character set?</p>", "options": ["128", "256", "64", "100"], "hint": "ASCII is a 7-bit character set — use the 2^n rule with n = 7."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>128</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores. 2^7 = 128.</li>\n</ul>\n</div>", "modelAnswer": "128 (2^7 = 128)."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:exam:1d6a450c', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'exam', 'mcq', 1, '{"num": "P9", "question": "<p>Using the Sample Code Table above, character <strong>B</strong> is 00001 and character <strong>C</strong> is 00010. Which binary code represents character <strong>D</strong>?</p>", "options": ["00011", "00100", "00101", "00010"], "caseStudy": "<p>A student invents a simplified character set for a school project, called the <strong>Sample Code Table (SCT-5)</strong>. It is <strong>not</strong> the real ASCII code — it is a made-up 5-bit set with only 20 characters, used here for practice.</p>\n<table>\n<tr><th>Character</th><th>Denary</th><th>5-bit binary code</th></tr>\n<tr><td>A</td><td>0</td><td>00000</td></tr>\n<tr><td>B</td><td>1</td><td>00001</td></tr>\n<tr><td>C</td><td>2</td><td>00010</td></tr>\n<tr><td>D</td><td>3</td><td>00011</td></tr>\n<tr><td>E</td><td>4</td><td>00100</td></tr>\n<tr><td>F</td><td>5</td><td>00101</td></tr>\n<tr><td>G</td><td>6</td><td>00110</td></tr>\n<tr><td>H</td><td>7</td><td>00111</td></tr>\n<tr><td>I</td><td>8</td><td>01000</td></tr>\n<tr><td>J</td><td>9</td><td>01001</td></tr>\n<tr><td>K</td><td>10</td><td>01010</td></tr>\n<tr><td>L</td><td>11</td><td>01011</td></tr>\n<tr><td>M</td><td>12</td><td>01100</td></tr>\n<tr><td>N</td><td>13</td><td>01101</td></tr>\n<tr><td>O</td><td>14</td><td>01110</td></tr>\n<tr><td>P</td><td>15</td><td>01111</td></tr>\n<tr><td>(space)</td><td>16</td><td>10000</td></tr>\n<tr><td>. (full stop)</td><td>17</td><td>10001</td></tr>\n<tr><td>, (comma)</td><td>18</td><td>10010</td></tr>\n<tr><td>! (exclamation mark)</td><td>19</td><td>10011</td></tr>\n</table>\n<p>The table has 20 characters in total, assigned sequentially starting from denary 0.</p>", "hint": "D is the very next character after C in the table — its code follows the same sequential pattern."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>00011</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores. D is denary 3 = 00011.</li>\n</ul>\n</div>", "modelAnswer": "00011 (D is denary 3 in the Sample Code Table)."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:exam:47455aae', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'exam', 'mcq', 1, '{"num": "P10", "question": "<p>Which of these statements about Unicode is TRUE?</p>", "options": ["Unicode always uses exactly 7 bits per character, the same as standard ASCII", "Unicode''s first 128 character codes are identical to the 128 codes used by ASCII", "Unicode can only represent the same characters as ASCII, just arranged differently", "Unicode uses fewer bits per character than ASCII, which is why it needs less storage space"], "caseStudy": "<p>A messaging app is used by people all around the world to send text messages, including messages containing emoji and characters from many different languages, such as Japanese, Arabic and Greek.</p>", "hint": "Think about how Unicode was designed to stay compatible with existing ASCII text."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>Unicode''s first 128 character codes are identical to the 128 codes used by ASCII</strong></li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores. Unicode uses MORE bits per character than ASCII, not fewer, and can represent far more characters than ASCII, not the same set.</li>\n</ul>\n</div>", "modelAnswer": "Unicode''s first 128 character codes are identical to the 128 codes used by ASCII."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:mcq:fd9ab5b9', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'mcq', 'mcq', 1, '{"question": "Which of these best defines a ''character set''?", "options": ["A single binary code value that is shared identically between every character a particular display device is able to show", "The set of characters a computer can represent, where each character has its own unique binary code", "A complete list of every symbol that physically appears on a standard computer keyboard", "The maximum number of characters that are allowed to fit inside one text file"]}'::jsonb, '{"answer": 1, "explain": "A character set is the set of characters a system can represent, with every character given its own unique binary code."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:mcq:e6c91d28', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'mcq', 'mcq', 1, '{"question": "How many different characters can be represented using 8 bits?", "options": ["256, since 2 to the power of 8 equals 256", "128, since 2 to the power of 7 equals 128", "64, since 2 to the power of 6 equals 64", "512, since 2 to the power of 9 equals 512"]}'::jsonb, '{"answer": 0, "explain": "2^8 = 256, so 8 bits can represent 256 different characters."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:mcq:01924e09', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'mcq', 'mcq', 1, '{"question": "What is the minimum number of bits needed to represent 100 different characters?", "options": ["7 bits, since 2 to the power of 7 (128) is enough but 2 to the power of 6 (64) is too small", "6 bits, since 100 is fairly close to 2 to the power of 6 (64) and rounds neatly to a whole byte value", "100 bits, using exactly one separate bit for every single character that is needed", "8 bits, chosen simply to match the size of one whole standard byte of memory"]}'::jsonb, '{"answer": 0, "explain": "2^6 = 64 is too small (64 < 100). 2^7 = 128 is big enough (128 ≥ 100). So the minimum is 7 bits."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:mcq:3c9cca6b', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'mcq', 'mcq', 1, '{"question": "The standard ASCII character set is usually described as using how many bits per character?", "options": ["7 bits, giving 2 to the power of 7 (128) possible characters", "8 bits, exactly matching the size of one whole byte", "16 bits, the same as a common Unicode encoding", "4 bits, exactly half of the eight bits used in one standard byte of memory"]}'::jsonb, '{"answer": 0, "explain": "ASCII is a 7-bit character set, giving 2^7 = 128 possible characters."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:mcq:778c6bcc', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'mcq', 'mcq', 1, '{"question": "How many different characters does the standard 7-bit ASCII character set contain?", "options": ["128 characters, since 2 to the power of 7 equals 128", "256 characters, since one whole byte is made up of 8 bits", "64 characters, since 2 to the power of 6 equals 64", "100 characters, a round number chosen for convenience"]}'::jsonb, '{"answer": 0, "explain": "2^7 = 128, so the standard ASCII character set contains 128 characters."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:mcq:a31c55f0', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'mcq', 'mcq', 1, '{"question": "ASCII characters are typically stored in modern computer memory using how many bits?", "options": ["8 bits (one byte) per character, even though ASCII itself only needs 7", "7 bits per character, with absolutely no extra bit ever used or reserved for anything else", "16 bits per character, exactly the same as a common Unicode encoding", "4 bits per character, exactly half of one whole byte"]}'::jsonb, '{"answer": 0, "explain": "Although ASCII itself only needs 7 bits, computers store data in whole bytes, so ASCII characters are typically stored using 8 bits (one byte) each."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:mcq:44559893', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'mcq', 'mcq', 1, '{"question": "A ticket machine uses a fictional code where letter A = 10, and each following letter increases by 1 (B = 11, C = 12, and so on). What code represents the letter D?", "options": ["13, since D is 3 letters after A in the sequence", "12, the code that is actually used for the letter C", "14, the code that comes two places after C", "10, the code that is actually used for the letter A"]}'::jsonb, '{"answer": 0, "explain": "D is 3 letters after A, so its code is 10 + 3 = 13."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:mcq:3015b981', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'mcq', 'mcq', 1, '{"question": "A messaging app needs to display text in English, Japanese and Arabic, plus emoji, within the same message. Which character set is better suited to this task?", "options": ["Unicode, because it uses more bits per character and so can represent far more characters", "ASCII, because its 128 characters already cover every language and every emoji currently in use around the world", "Unicode, because it always uses fewer bits per character than ASCII does", "ASCII, because it was specifically designed for use inside messaging apps"]}'::jsonb, '{"answer": 0, "explain": "Unicode uses more bits per character than ASCII, allowing it to represent the huge range of characters needed for multiple languages and emoji, which ASCII''s 128 codes cannot cover."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:mcq:71ca135d', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'mcq', 'mcq', 1, '{"question": "A text file is re-encoded so that every character uses 16 bits instead of 8 bits, with no change to the number of characters. What effect does this have on the file''s size?", "options": ["The file size roughly doubles, since twice as many bits are stored per character", "The file size stays exactly the same, since the number of characters has not changed", "The file size is roughly halved, since Unicode compresses text as it is stored", "The file becomes exactly sixteen times larger than it was before"]}'::jsonb, '{"answer": 0, "explain": "Doubling the number of bits used per character (from 8 to 16), with the same number of characters, roughly doubles the total number of bits stored — and so roughly doubles the file size."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:mcq:3912ed37', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'mcq', 'mcq', 1, '{"question": "Which statement correctly describes the relationship between Unicode and ASCII?", "options": ["Unicode''s first 128 character codes are identical to the 128 codes used by ASCII", "Unicode and ASCII are completely unrelated character sets that share no codes at all", "ASCII is simply a shortened, 64-character version of the full Unicode character set", "Unicode replaced ASCII entirely, so ASCII codes are no longer valid anywhere today"]}'::jsonb, '{"answer": 0, "explain": "Unicode was designed so its first 128 codes exactly match ASCII''s 128 codes, keeping existing ASCII text valid within Unicode."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:mcq:3f6b016a', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'mcq', 'mcq', 1, '{"question": "In a sequential character code, character M has the code 01100, and N is the very next character in the set. What binary code represents N?", "options": ["01101, one more than M''s own code of 01100", "01011, one less than M''s own code of 01100", "01110, two more than M''s own code of 01100", "01100, exactly the same code as M itself"]}'::jsonb, '{"answer": 0, "explain": "Sequential codes increase by 1 for the next character in the set, and 01100 (12) + 1 = 01101 (13)."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:mcq:09913a77', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'mcq', 'mcq', 1, '{"question": "A retro games console can only spare 4 bits to store each character''s code. What is the maximum number of distinct characters it could support?", "options": ["16 characters, since 2 to the power of 4 equals 16", "4 characters, exactly one for each bit that is available", "8 characters, exactly half of the usual byte-sized total", "32 characters, exactly double the usual estimate given"]}'::jsonb, '{"answer": 0, "explain": "2^4 = 16, so a 4-bit code can support a maximum of 16 distinct characters."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:tf:a038af79', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'tf', 'tf', 1, '{"question": "A character set is the collection of characters a computer can represent, each with its own unique binary code."}'::jsonb, '{"answer": true, "explain": "Correct — that is exactly what a character set is."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:tf:de7350d4', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'tf', 'tf', 1, '{"question": "Using 5 bits, a computer could represent up to 64 different characters."}'::jsonb, '{"answer": false, "explain": "5 bits gives 2^5 = 32 different characters, not 64. 64 would need 6 bits (2^6 = 64)."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:tf:e87e84cb', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'tf', 'tf', 1, '{"question": "The standard ASCII character set itself uses 8 bits to represent every character."}'::jsonb, '{"answer": false, "explain": "ASCII itself is a 7-bit character set (128 characters). It is commonly STORED using 8 bits (one byte), but the code itself only needs 7 bits."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:tf:6612267f', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'tf', 'tf', 1, '{"question": "ASCII can represent letters, digits, punctuation marks and control codes."}'::jsonb, '{"answer": true, "explain": "Correct — ASCII''s 128 characters include upper- and lower-case letters, digits 0–9, punctuation marks and non-printable control codes."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:tf:8e50fc9f', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'tf', 'tf', 1, '{"question": "Because character codes are usually assigned sequentially, the code for a letter is always exactly one more than the code for the letter before it in the alphabet."}'::jsonb, '{"answer": true, "explain": "True for sequential character sets like ASCII — consecutive letters have consecutive binary codes."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:tf:302369da', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'tf', 'tf', 1, '{"question": "Unicode uses fewer bits per character than ASCII, which is why it can represent more characters."}'::jsonb, '{"answer": false, "explain": "The opposite is true: Unicode uses MORE bits per character than ASCII, which is exactly why it can represent far more characters."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:tf:d455fe82', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'tf', 'tf', 1, '{"question": "The first 128 character codes in Unicode are identical to the 128 codes in ASCII."}'::jsonb, '{"answer": true, "explain": "Correct — Unicode was deliberately designed this way, so existing ASCII text is automatically valid Unicode text too."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:tf:038b8ae4', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'tf', 'tf', 1, '{"question": "Storing text using Unicode instead of ASCII can make a text file larger, because Unicode often uses more bits per character."}'::jsonb, '{"answer": true, "explain": "Correct — more bits per character, with the same number of characters, means more bits (and so more storage) are needed overall."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:learn:bb5b180e', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'learn', 'mcq', 1, '{"readingTitle": "What is a character set, and why does every character need a unique code?", "reading": "<h4>Every character needs its own binary code</h4>\n<ul>\n<li>Just like numbers, every <strong>character</strong> a computer can store or display — a letter, a digit, a punctuation mark, even a space — has to be represented using <strong>binary digits (bits)</strong>, because that is the only form of data computer hardware can physically store.</li>\n<li>A <strong>character set</strong> is the collection of characters a computer system can represent. Every character in that set is given its own <strong>unique binary code</strong> — no two characters in the same set share the same code, or the computer would not be able to tell them apart.</li>\n<li>When a computer stores text, it isn''t storing the letters themselves — it is storing a sequence of these binary codes, one per character, and looking each one up in the character set whenever it needs to display or process the text.</li>\n</ul>\n<h4>Encoding and decoding</h4>\n<ul>\n<li><strong>Encoding</strong> is converting a character into its binary code, using the character set as a lookup.</li>\n<li><strong>Decoding</strong> is the reverse: converting a binary code back into the character it represents.</li>\n<li>Both directions rely on every device involved using the <strong>same character set</strong>. If a file is encoded with one character set but decoded using a different one, the wrong characters (often strange symbols) can appear on screen.</li>\n</ul>", "question": "What is a character set?", "options": ["A single binary code value that is shared identically between every character a particular display device is able to show", "The collection of characters a computer can represent, where each character has its own unique binary code", "A complete list of every symbol that physically appears on a standard computer keyboard", "The maximum number of characters that are allowed to fit inside one text file"]}'::jsonb, '{"answer": 1, "explain": "A character set is the collection of characters a system can represent, with every character given its own unique binary code so the computer can tell them apart."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:learn:adaaa10a', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'learn', 'mcq', 1, '{"readingTitle": "How many characters can n bits represent — and how few bits do you need?", "reading": "<h4>The 2ⁿ rule</h4>\n<ul>\n<li>If a character set uses <strong>n bits</strong> for every character''s code, the number of <strong>different characters</strong> it can represent is <strong>2 to the power of n (2ⁿ)</strong> — because each of the n bits can independently be 0 or 1.</li>\n<li>This is the same 2ⁿ rule used elsewhere on this course for counting how many different values a binary pattern can represent. It is not a special rule invented just for characters.</li>\n</ul>\n<table>\n<tr><th>Bits (n)</th><th>Characters (2ⁿ)</th></tr>\n<tr><td>1</td><td>2</td></tr>\n<tr><td>2</td><td>4</td></tr>\n<tr><td>3</td><td>8</td></tr>\n<tr><td>4</td><td>16</td></tr>\n<tr><td>5</td><td>32</td></tr>\n<tr><td>6</td><td>64</td></tr>\n<tr><td>7</td><td>128</td></tr>\n<tr><td>8</td><td>256</td></tr>\n</table>\n<h4>Working backwards: how many bits do you need?</h4>\n<ul>\n<li>Exam questions often flip the question around: <em>\"a system needs to represent 50 different characters — what is the minimum number of bits per character?\"</em></li>\n<li>The method: try increasing values of n in 2ⁿ until the result is <strong>greater than or equal to</strong> the number of characters needed. The FIRST n that works is the minimum.</li>\n</ul>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>A system needs 50 characters. Try n = 5: work out 2⁵.</td><td>32 — too small (32 &lt; 50)</td></tr>\n<tr><td>2</td><td>Try n = 6: work out 2⁶.</td><td>64 — big enough (64 ≥ 50)</td></tr>\n<tr><td>3</td><td>State the minimum n that works.</td><td>6 bits</td></tr>\n</table>", "question": "What is the minimum number of bits needed to represent 200 different characters?", "options": ["7 bits, since 2 to the power of 7 (128) is reasonably close to the target of 200 characters needed", "8 bits, since 2 to the power of 7 (128) is too small but 2 to the power of 8 (256) is enough", "200 bits, using exactly one separate bit for every character that is needed", "100 bits, using exactly half as many bits as the number of characters needed"]}'::jsonb, '{"answer": 1, "explain": "2^7 = 128 is too small (128 < 200). 2^8 = 256 is big enough (256 ≥ 200). So the minimum is 8 bits."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:learn:91ef2688', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'learn', 'mcq', 1, '{"readingTitle": "ASCII: the standard 7-bit character set", "reading": "<h4>What ASCII is</h4>\n<ul>\n<li><strong>ASCII</strong> (American Standard Code for Information Interchange) is a standard <strong>7-bit</strong> character set. Using the 2ⁿ rule, 7 bits can represent 2⁷ = <strong>128 different characters</strong>.</li>\n<li>Those 128 characters include the <strong>upper- and lower-case English letters</strong>, the <strong>digits 0–9</strong>, common <strong>punctuation marks</strong> (such as . , ! ?), and a set of <strong>control codes</strong> — non-printable codes that control a device rather than display a symbol (for example, codes that mean \"start a new line\" or \"delete the last character\").</li>\n</ul>\n<h4>How ASCII is actually stored</h4>\n<ul>\n<li>Although ASCII itself only needs 7 bits, modern computers store data in whole <strong>bytes (8 bits)</strong>. So an ASCII character is almost always stored using <strong>one byte</strong> per character, with the extra bit either left unused or used for another purpose (such as error-checking).</li>\n<li>This is why exam questions sometimes describe ASCII text as \"8 bits per character\" in a scenario. Always use the number of bits <strong>given in the question</strong> for any calculation, rather than assuming 7 or 8 from memory.</li>\n</ul>\n<h4>What you are NOT expected to know</h4>\n<ul>\n<li>You do not need to <strong>memorise</strong> the exact binary or denary code for any real ASCII character. Exam questions always give you the character set (real or invented) that you need for a particular task.</li>\n</ul>", "question": "How many characters can the standard 7-bit ASCII character set represent?", "options": ["128 characters, because 2 to the power of 7 equals 128", "256 characters, because one whole byte is made up of 8 bits", "64 characters, because 2 to the power of 6 equals 64", "There is no fixed limit on how many characters ASCII can represent"]}'::jsonb, '{"answer": 0, "explain": "ASCII is a 7-bit character set, and 2^7 = 128, so it can represent 128 different characters."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:learn:bf311509', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'learn', 'mcq', 1, '{"readingTitle": "Worked example: encoding and decoding with an invented code table", "reading": "<h4>An invented character set for practice</h4>\n<p>The table below is a small, <strong>made-up</strong> 5-bit character set — the <strong>Sample Code Table (SCT-5)</strong> — invented for practice on this page. It is <strong>not</strong> the real ASCII code.</p>\n<table>\n<tr><th>Character</th><th>Denary</th><th>5-bit code</th></tr>\n<tr><td>A</td><td>0</td><td>00000</td></tr>\n<tr><td>B</td><td>1</td><td>00001</td></tr>\n<tr><td>C</td><td>2</td><td>00010</td></tr>\n<tr><td>D</td><td>3</td><td>00011</td></tr>\n<tr><td>E</td><td>4</td><td>00100</td></tr>\n<tr><td>…</td><td>…</td><td>…</td></tr>\n<tr><td>P</td><td>15</td><td>01111</td></tr>\n<tr><td>(space)</td><td>16</td><td>10000</td></tr>\n</table>\n<p>SCT-5 defines 20 characters in total (A–P, plus a space, full stop, comma and exclamation mark), assigned <strong>sequentially</strong> starting from denary 0. Since 2⁴ = 16 is too small for 20 characters but 2⁵ = 32 is enough, every code needs <strong>5 bits</strong>.</p>\n<h4>Worked example: encoding a word</h4>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>Encode the word \"BE\" using SCT-5. Look up B.</td><td>B = denary 1 = 00001</td></tr>\n<tr><td>2</td><td>Look up E.</td><td>E = denary 4 = 00100</td></tr>\n<tr><td>3</td><td>Write the codes in order.</td><td>00001 00100</td></tr>\n</table>\n<h4>Worked example: decoding a binary string</h4>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>Decode 01100 10000. Convert the first code to denary.</td><td>01100 = 12</td></tr>\n<tr><td>2</td><td>Look up denary 12 in the table.</td><td>12 = M</td></tr>\n<tr><td>3</td><td>Convert and look up the second code.</td><td>10000 = 16 = (space)</td></tr>\n</table>", "question": "Using SCT-5 (A=00000, B=00001, C=00010, D=00011…), what is the binary code for the character D?", "options": ["00011, since D is the 4th character in the table, denary 3, one place after C", "00010, the code that is actually used for the earlier character C, not the character D", "00100, the code that comes two full places after C in the table, not the character D", "00001, the code that is actually used for the earlier character B, not the character D"]}'::jsonb, '{"answer": 0, "explain": "D is the 4th character in SCT-5, denary 3, which is 00011 in 5-bit binary."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:learn:97d79e81', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'learn', 'mcq', 1, '{"readingTitle": "Why character codes are sequential — working out an ''unknown'' character logically", "reading": "<h4>Codes are assigned in order</h4>\n<ul>\n<li>In ASCII (and in most character sets, including the invented ones on this page), letters and digits are given <strong>sequential</strong> binary codes — the code for the next letter in the alphabet is exactly <strong>one more</strong> than the code for the letter before it.</li>\n<li>This means that if you are given the code for one character, you can work out the code for a nearby character just by counting how many places along the sequence it is. You do not need to memorise every individual code.</li>\n</ul>\n<h4>Worked example: a fixed offset between upper and lower case</h4>\n<p>Suppose a fictional character code, <strong>Code X</strong>, assigns uppercase <strong>A</strong> the denary code <strong>40</strong>, with every following letter one more than the last (B = 41, C = 42, and so on). Lowercase letters use the <strong>same code as the matching uppercase letter, plus a fixed offset of 50</strong>.</p>\n<table>\n<tr><th>Step</th><th>What you do</th><th>Result</th></tr>\n<tr><td>1</td><td>Find the code for uppercase D. Count how many letters after A it is (3), and add to 40.</td><td>40 + 3 = 43</td></tr>\n<tr><td>2</td><td>Find the code for lowercase d. Add the fixed lowercase offset of 50 to uppercase D''s code.</td><td>43 + 50 = 93</td></tr>\n</table>\n<h4>Why the exam tests this</h4>\n<ul>\n<li>Questions that give you one or two known codes from a set, then ask for a nearby one, are testing whether you understand that the codes are <strong>sequential</strong> and that related pairs (like upper/lower case) sit a <strong>fixed distance</strong> apart — not whether you have memorised any real code table.</li>\n</ul>", "question": "In a sequential character code, if the letter G has the code 38, what is the most likely code for the letter H (the very next letter)?", "options": ["39, since codes increase by 1 for each next letter", "37, since this mistakenly uses the code that came BEFORE G rather than after it", "76, since this doubles G''s code instead of simply adding one for the next letter", "19, since this halves G''s code instead of simply adding one for the next letter"]}'::jsonb, '{"answer": 0, "explain": "Sequential codes increase by exactly 1 for each following letter in the alphabet, so H would be 38 + 1 = 39."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:learn:a9c0906f', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'learn', 'mcq', 1, '{"readingTitle": "Unicode: a bigger character set for a multilingual world", "reading": "<h4>Why ASCII wasn''t enough</h4>\n<ul>\n<li>ASCII''s 128 characters are enough for basic English text, but nowhere near enough to represent the letters used by <strong>every language in the world</strong> (such as Chinese, Arabic or Greek scripts), or the huge range of <strong>symbols and emoji</strong> used in modern digital communication.</li>\n<li><strong>Unicode</strong> is a much larger character set, designed to solve this problem by using <strong>more bits per character</strong> than ASCII — for example, 16 bits instead of ASCII''s 7. Using the 2ⁿ rule, 16 bits can represent 2¹⁶ = 65,536 different characters, far more than ASCII''s 128.</li>\n</ul>\n<h4>Unicode stays compatible with ASCII</h4>\n<ul>\n<li>Unicode was deliberately designed so that its <strong>first 128 character codes are identical</strong> to ASCII''s 128 codes. This means any text that was valid ASCII is automatically valid Unicode too — older ASCII files do not need to be converted or become unreadable.</li>\n</ul>\n<h4>The storage trade-off</h4>\n<ul>\n<li>Using more bits per character is not free: a Unicode character typically takes up <strong>more storage</strong> than the same character stored in ASCII, because more bits are needed for every single character in the file.</li>\n<li>This means a text file re-encoded from ASCII into Unicode, containing exactly the same characters, will usually become a <strong>larger file</strong>. Representing more possible characters comes at the cost of more bits needed per character.</li>\n</ul>", "question": "What is the main storage trade-off of using Unicode instead of ASCII?", "options": ["Unicode files are always smaller, because Unicode compresses data automatically as it is stored", "Unicode characters typically use more bits, so the same amount of text becomes a larger file", "Unicode removes the need to store any control codes at all, which saves storage space", "Unicode text can only ever be stored using exactly 8 bits per character"]}'::jsonb, '{"answer": 1, "explain": "Unicode characters typically use more bits per character than ASCII, so storing the same text in Unicode usually results in a larger file."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:misc:fee05aef', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing you need to memorise the exact binary or denary code for every real ASCII character.</p><p><strong>✅ The correct idea:</strong> OCR does <strong>not</strong> expect you to memorise real ASCII codes — exam questions always give you the character set (or the codes) you need, often an invented one. What you must understand instead is the <em>relationship</em> between bits and how many characters they can represent, and how sequential codes let you work out an ''unknown'' character logically.</p>", "question": "Which of these does the OCR specification actually require you to know for this topic?", "options": ["The exact real ASCII code number for every single character, memorised completely off by heart", "How the number of bits used relates to the number of characters that can be represented", "The precise binary code used for every emoji defined inside Unicode", "The complete Unicode code for every written language used around the world"]}'::jsonb, '{"answer": 1, "explain": "You are not expected to memorise real codes — you are expected to understand the relationship between bits and representable characters, and how sequential codes work."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:misc:76de0846', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Assuming that using more bits per character makes text look better or higher quality, in the same way that a higher colour depth improves an image.</p><p><strong>✅ The correct idea:</strong> Text doesn''t have a ''quality'' scale the way images and sound do. Using <strong>more bits per character</strong> simply means <strong>more different characters can be represented</strong> — a bigger character set covering more languages, symbols and emoji — it does not make any individual character look sharper or clearer on screen.</p>", "question": "What does using MORE bits per character actually give a character set?", "options": ["Sharper, higher-quality looking text displayed on the screen for the user", "The ability to represent a larger number of different characters", "Noticeably faster processing of each individual character by the CPU", "A smaller file size for storing exactly the same amount of text"]}'::jsonb, '{"answer": 1, "explain": "More bits per character means more possible codes, so more different characters can be represented — it has no effect on how ''sharp'' text looks."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:misc:327d1c5d', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Thinking ASCII and Unicode are two totally separate, incompatible systems that cannot be mixed together.</p><p><strong>✅ The correct idea:</strong> Unicode was deliberately designed so its <strong>first 128 character codes are identical</strong> to ASCII''s 128 codes. This means any valid ASCII text is automatically valid Unicode text too — Unicode extends ASCII rather than replacing it with something incompatible.</p>", "question": "How does Unicode relate to the older ASCII character set?", "options": ["They are unrelated systems that were never designed to work together", "Unicode''s first 128 codes are identical to the 128 codes used by ASCII", "Unicode completely replaced ASCII, so ASCII text no longer works anywhere", "ASCII is a newer, improved version of Unicode released after it"]}'::jsonb, '{"answer": 1, "explain": "Unicode''s first 128 codes exactly match ASCII''s, which is why existing ASCII text remains valid Unicode text."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:misc:49177300', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Believing the 2ⁿ rule for counting representable characters only works for the specific cases of n = 7 or n = 8 bits.</p><p><strong>✅ The correct idea:</strong> 2ⁿ is a <strong>general rule</strong> that works for any whole number of bits n — 3 bits give 2³ = 8 characters, 5 bits give 2⁵ = 32, and so on. 7 bits (ASCII) and 8 bits (one byte) are simply the two examples that come up most often, not special cases governed by a different rule.</p>", "question": "Using the general 2ⁿ rule, how many different characters could a 3-bit character set represent?", "options": ["3 characters, one for every bit that is available", "6 characters, double the number of bits available", "8 characters, since 2 to the power of 3 equals 8", "9 characters, three squared using the number of bits"]}'::jsonb, '{"answer": 2, "explain": "2^3 = 8, so a 3-bit character set can represent 8 different characters."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:misc:d889145a', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> When asked for the minimum number of bits needed to represent N characters, using N itself as the number of bits — for example saying ''50 characters needs 50 bits''.</p><p><strong>✅ The correct idea:</strong> You need the <strong>smallest n</strong> for which 2ⁿ is <strong>greater than or equal to</strong> N — not N itself. For 50 characters: 2⁵ = 32 is too small, but 2⁶ = 64 is enough, so the answer is <strong>6 bits</strong>, not 50 bits.</p>", "question": "What is the minimum number of bits needed to represent 20 different characters?", "options": ["20 bits, using exactly one separate bit for every single character that this needs to store", "4 bits, since 2 to the power of 4 (16) is reasonably close to the number 20", "5 bits, since 2 to the power of 4 (16) is too small but 2 to the power of 5 (32) is enough", "6 bits, simply one more than the previous minimum just to be extra safe"]}'::jsonb, '{"answer": 2, "explain": "2^4 = 16 is too small (16 < 20). 2^5 = 32 is enough (32 ≥ 20). So the minimum is 5 bits."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:tips:b2fe2ff0', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'tips', 'mcq', 1, '{"readingTitle": "explain — Show-your-working ladder: the 2-mark ''how many bits'' calculation", "reading": "<p>A typical question: <em>\"A system needs to represent 40 different characters. Calculate the minimum number of bits required per character. Show your working.\"</em> [2 marks] Here is the same answer at every level:</p>\n\n<p><strong>❌ 0 marks:</strong> \"6\"</p>\n<ul>\n<li>No working shown at all. Even a correct final answer with nothing behind it risks losing the working mark entirely if a small slip means the number given is actually wrong.</li>\n</ul>\n\n<p><strong>⚠️ 1 mark:</strong> \"2^5 = 32, 2^6 = 64\"</p>\n<ul>\n<li>Valid working is shown, testing the powers of 2 against 40 (1 mark) — but no final answer is actually stated, so the second mark for the answer itself is not awarded.</li>\n</ul>\n\n<p><strong>✅ 2 marks:</strong> \"2^5 = 32, too small <strong>(1)</strong>. 2^6 = 64, big enough. Minimum = 6 bits <strong>(1)</strong>.\"</p>\n\n<p><strong>Why this matters even if your arithmetic slips:</strong> OCR-style marking splits the WORKING and the ANSWER into separate marks. If your method (testing powers of 2 against the target number) is correct but you make a small slip in one power of 2, you can still keep the working mark — but only if you actually wrote the working down.</p>", "question": "You correctly show that 2^5 = 32 is too small, but then wrongly calculate 2^6 as 60 instead of 64 and conclude ''minimum = 6 bits''. What mark do you get out of 2?", "options": ["0, because the working used to reach the final answer contained an arithmetic slip", "1, since valid working testing powers of 2 against the target is clearly shown", "2, since the final stated answer of 6 bits happens to still be correct", "It depends entirely on which specific exam paper the question came from"]}'::jsonb, '{"answer": 1, "explain": "Testing powers of 2 against the target number is valid working, so it earns the working mark even though one of the calculated values (2^6 = 60) was arithmetically wrong."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:tips:9c9eaf1f', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'tips', 'mcq', 1, '{"readingTitle": "tip — Answering tick-one-box ASCII/Unicode fact questions: eliminate, don''t guess", "reading": "<p>Single tick-box questions about ASCII and Unicode facts are worth only 1 mark, but they are rarely a lucky guess — three of the four options are usually wrong for a specific, checkable reason.</p>\n\n<p><strong>The reliable method:</strong> test EVERY option against something you know for certain before you tick anything:</p>\n<ul>\n<li>Does the option confuse the number of BITS with the number of CHARACTERS (e.g. mixing up \"7 bits\" with \"128 characters\")?</li>\n<li>Does the option get the direction of the ASCII/Unicode comparison backwards (saying Unicode uses FEWER bits, when it actually uses more)?</li>\n<li>Does the option claim ASCII and Unicode are unrelated, when Unicode''s first 128 codes are actually identical to ASCII''s?</li>\n</ul>\n\n<p><strong>One tick only.</strong> As with other tick-one-box questions on this course, ticking two or more boxes scores zero, even if one of them is correct — so commit to your single best-evidenced answer rather than hedging between two options.</p>", "question": "You are fairly confident the answer is option 2, but tick option 4 as well just in case. What mark do you get?", "options": ["1 mark, since option 2 was in fact the option that was correct", "0 marks — ticking two or more boxes always scores zero on these questions", "0.5 marks, awarded automatically for showing genuine uncertainty", "It depends entirely on which of the two ticked options the marker prefers"]}'::jsonb, '{"answer": 1, "explain": "Tick-one-box questions award 0 marks the moment two or more boxes are ticked, regardless of whether the correct option is among them."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:tips:ea7f49d3', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'tips', 'mcq', 1, '{"readingTitle": "explain — Command-word ladder: ''explain'' the ASCII/Unicode storage trade-off", "reading": "<p>A typical question: <em>\"Explain why choosing to store text using Unicode instead of ASCII could increase the file size.\"</em> [up to 4 marks] \"Explain\" needs a point AND a development — \"…which means…\" — not just a fact on its own.</p>\n\n<p><strong>❌ 0–1 marks:</strong> \"Unicode uses more bits.\"</p>\n<ul>\n<li>A bare fact with no development. It is TRUE, but it does not explain why the file size increases as a result.</li>\n</ul>\n\n<p><strong>⚠️ 2 marks:</strong> \"Unicode uses more bits per character than ASCII, which means each character takes up more storage.\"</p>\n<ul>\n<li>One point developed with \"…which means…\" — a genuine explanation, but it stops short of a full comparison and a stated consequence for the whole file.</li>\n</ul>\n\n<p><strong>✅ 3–4 marks:</strong> \"Unicode uses more bits per character than ASCII (for example 16 bits instead of 7), which means every single character needs more storage space. Because a text file contains many characters, this extra amount per character adds up across the whole file, which means the total file size becomes larger than the same text stored in ASCII.\"</p>\n\n<p><strong>The pattern:</strong> fact (more bits per character) → development (more storage per character) → consequence (the WHOLE FILE grows, not just one character). Each arrow is worth developing into its own sentence.</p>", "question": "A student writes only ''Unicode uses more bits, so files are bigger'' for a 4-mark ''explain'' question. Roughly how many marks is this likely to gain?", "options": ["Full marks, since the key fact and its consequence are both technically present", "Only partial marks, since the chain of reasoning is not developed step by step", "Zero marks, since the statement given is factually incorrect", "It cannot be marked at all without a diagram accompanying the answer"]}'::jsonb, '{"answer": 1, "explain": "The statement is correct but underdeveloped — a full-marks ''explain'' answer needs each step in the chain (more bits per character → more storage per character → larger overall file) spelled out, not compressed into one bare sentence."}'::jsonb),
('computer-science:1-2-5-data-storage-characters:fib:39e626a3', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'fib', 'fib', 1, '{"question": "A _____ is the set of characters a computer can represent, where each character has its own unique binary code.", "blankOptions": {"B1": ["ASCII", "character set", "bits", "7"]}}'::jsonb, '{"blanks": {"B1": "character set"}}'::jsonb),
('computer-science:1-2-5-data-storage-characters:fib:1d3e722c', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'fib', 'fib', 1, '{"question": "Using 7 bits, a character set can represent up to _____ different characters.", "blankOptions": {"B1": ["128", "bits", "byte", "character set"]}}'::jsonb, '{"blanks": {"B1": "128"}}'::jsonb),
('computer-science:1-2-5-data-storage-characters:fib:6e3e36ed', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'fib', 'fib', 1, '{"question": "Using 8 bits, a character set can represent up to _____ different characters.", "blankOptions": {"B1": ["128", "256", "character set", "ASCII"]}}'::jsonb, '{"blanks": {"B1": "256"}}'::jsonb),
('computer-science:1-2-5-data-storage-characters:fib:e91377cd', 'computer-science', 'computer-science:1-2-5-data-storage-characters', '1.2.5 Data Storage: Characters', 'fib', 'fib', 1, '{"question": "The standard ASCII character set uses _____ bits to represent each character.", "blankOptions": {"B1": ["character set", "byte", "128", "7"]}}'::jsonb, '{"blanks": {"B1": "7"}}'::jsonb),
